.toggle-slider {
    position: absolute;
    cursor: pointer;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: #30363d;
    transition: 0.3s;
    border-radius: 22px;
}
.toggle-slider:before {
    position: absolute;
    content: "";
    height: 16px;
    width: 16px;
    left: 3px;
    bottom: 3px;
    background-color: #e0e6f0;
    transition: 0.3s;
    border-radius: 50%;
}
input:checked + .toggle-slider {
    background-color: #238636;
}
input:checked + .toggle-slider:before {
    transform: translateX(18px);
}

/* æå éĒæŋæ ·åž */
.collapsible-section {
    background: #161b22;
    border: 1px solid #21262d;
    border-radius: 8px;
    margin-bottom: 12px;
    overflow: hidden;
}
.collapsible-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px 12px;
    cursor: pointer;
    background: #0d1117;
    transition: background 0.2s;
}
.collapsible-header:hover {
    background: #161b22;
}
.collapse-icon {
    color: #8b949e;
    font-size: 12px;
    transition: transform 0.2s;
}
.collapsible-section.collapsed .collapse-icon {
    transform: rotate(-90deg);
}
.collapsible-content {
    padding: 12px;
    max-height: 1000px;
    overflow: hidden;
    transition: max-height 0.3s ease-out, padding 0.3s;
}
.collapsible-section.collapsed .collapsible-content {
    max-height: 0;
    padding: 0 12px;
}
.section-subtitle {
    font-size: 12px;
    color: #6e7681;
    margin: 8px 0 4px;
    padding-top: 8px;
    border-top: 1px solid #21262d;
}
.section-subtitle:first-child {
    border-top: none;
    padding-top: 0;
}
</style>


